 1→import { useCallback, useEffect, useRef, useState } from "react";
 2→import type { SearchEntityResponse } from "../../shared/contracts";
 3→import { useWorkspaceState } from "../stores/workspace-state";
 4→
 5→type UseEntitySearchReturn = {
 6→  results: SearchEntityResponse[];
 7→  isSearching: boolean;
 8→  query: string;
 9→  setQuery: (q: string) => void;
10→};
11→
12→export function useEntitySearch(): UseEntitySearchReturn {
13→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
14→  const [query, setQuery] = useState("");
15→  const [results, setResults] = useState<SearchEntityResponse[]>([]);
16→  const [isSearching, setIsSearching] = useState(false);
17→  const abortRef = useRef<AbortController | undefined>(undefined);
18→  const timerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
19→
20→  const search = useCallback(
21→    async (q: string) => {
22→      if (!workspaceId || !q.trim()) {
23→        setResults([]);
24→        setIsSearching(false);
25→        return;
26→      }
27→
28→      abortRef.current?.abort();
29→      const controller = new AbortController();
30→      abortRef.current = controller;
31→
32→      setIsSearching(true);
33→      const params = new URLSearchParams({
34→        q: q.trim(),
35→        workspaceId,
36→        limit: "20",
37→      });
38→
39→      try {
40→        const response = await fetch(`/api/entities/search?${params}`, {
41→          signal: controller.signal,
42→        });
43→        if (!response.ok) throw new Error(await response.text());
44→        const data = (await response.json()) as SearchEntityResponse[];
45→        if (!controller.signal.aborted) {
46→          setResults(data);
47→        }
48→      } catch (err) {
49→        if (err instanceof DOMException && err.name === "AbortError") return;
50→        if (!controller.signal.aborted) {
51→          setResults([]);
52→        }
53→      } finally {
54→        if (!controller.signal.aborted) {
55→          setIsSearching(false);
56→        }
57→      }
58→    },
59→    [workspaceId],
60→  );
61→
62→  useEffect(() => {
63→    if (timerRef.current) clearTimeout(timerRef.current);
64→
65→    if (!query.trim()) {
66→      setResults([]);
67→      setIsSearching(false);
68→      return;
69→    }
70→
71→    setIsSearching(true);
72→    timerRef.current = setTimeout(() => {
73→      void search(query);
74→    }, 300);
75→
76→    return () => {
77→      if (timerRef.current) clearTimeout(timerRef.current);
78→    };
79→  }, [query, search]);
80→
81→  useEffect(() => {
82→    return () => {
83→      abortRef.current?.abort();
84→    };
85→  }, []);
86→
87→  return { results, isSearching, query, setQuery };
88→}
