13→  const [activeFilter, setActiveFilter] = useState<EntityKind | "all">("all");
14→  const inputRef = useRef<HTMLInputElement>(null);
15→
16→  const filteredResults =
17→    activeFilter === "all"
18→      ? results
19→      : results.filter((r) => r.kind === activeFilter);
20→
21→  useEffect(() => {
22→    inputRef.current?.focus();
23→  }, []);
24→
25→  useEffect(() => {
26→    function handleKeyDown(e: KeyboardEvent) {
27→      if (e.key === "Escape") onClose();
28→    }
29→    document.addEventListener("keydown", handleKeyDown);
30→    return () => document.removeEventListener("keydown", handleKeyDown);
31→  }, [onClose]);
32→
33→  return (
34→    <div className="search-overlay-backdrop" onClick={onClose}>
35→      <div className="search-overlay" onClick={(e) => e.stopPropagation()}>
36→        <div className="search-overlay-header">
