  1→import { RecordId } from "surrealdb";
  2→import type { SearchEntityResponse } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import { resolveWorkspaceProjectRecord, resolveWorkspaceRecord } from "../workspace/workspace-scope";
  8→
  9→type SearchEntityRow = {
 10→  id: RecordId<"task" | "decision" | "question", string>;
 11→  kind: "task" | "decision" | "question";
 12→  text: string;
 13→  confidence: number;
 14→  sourceMessage: RecordId<"message", string>;
 15→};
 16→
 17→export function createEntitySearchHandler(deps: ServerDependencies): (url: URL) => Promise<Response> {
 18→  return (url: URL) => handleEntitySearch(deps, url);
 19→}
 20→
 21→async function handleEntitySearch(deps: ServerDependencies, url: URL): Promise<Response> {
 22→  const startedAt = performance.now();
 23→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 24→  if (!workspaceId) {
 25→    return jsonError("workspaceId is required", 400);
 26→  }
 27→
 28→  const projectId = url.searchParams.get("projectId")?.trim();
 29→
 30→  const query = url.searchParams.get("q")?.trim().toLowerCase();
 31→  if (!query) {
 32→    return jsonError("q is required", 400);
 33→  }
 34→
 35→  const rawLimit = url.searchParams.get("limit");
 36→  const parsedLimit = Number(rawLimit ?? "10");
 37→  if (!Number.isFinite(parsedLimit) || parsedLimit < 1) {
 38→    return jsonError("limit must be a positive number", 400);
 39→  }
 40→
 41→  const limit = Math.min(Math.floor(parsedLimit), 100);
 42→  logDebug("http.request.validated", "Entity search request validated", {
 43→    workspaceId,
 44→    projectId,
 45→    limit,
 46→    queryLength: query.length,
 47→  });
 48→  logInfo("entity.search.started", "Entity search started", {
 49→    workspaceId,
 50→    projectId,
 51→    limit,
 52→  });
 53→
 54→  let workspaceRecord: RecordId<"workspace", string>;
 55→  let projectRecord: RecordId<"project", string> | undefined;
 56→
 57→  try {
 58→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 59→    if (projectId) {
 60→      projectRecord = await resolveWorkspaceProjectRecord(deps.surreal, workspaceRecord, projectId);
 61→    }
 62→  } catch (error) {
 63→    if (error instanceof HttpError) {
 64→      logWarn("entity.search.http_error", "Entity search failed with client-facing error", {
 65→        workspaceId,
 66→        projectId,
 67→        statusCode: error.status,
 68→      });
 69→      return jsonError(error.message, error.status);
 70→    }
 71→
 72→    logError("entity.search.scope_validation.failed", "Entity search scope validation failed", error, {
 73→      workspaceId,
 74→      projectId,
 75→    });
 76→    const errorText = error instanceof Error ? error.message : "failed to validate scope";
 77→    return jsonError(errorText, 500);
 78→  }
 79→
 80→  const [rows] = projectRecord
 81→    ? await deps.surreal
 82→        .query<[SearchEntityRow[]]>(
 83→          "RETURN fn::entity_search_project($query, $limit, $workspace, $project);",
 84→          {
 85→            query,
 86→            limit,
 87→            workspace: workspaceRecord,
 88→            project: projectRecord,
 89→          },
 90→        )
 91→        .collect<[SearchEntityRow[]]>()
 92→    : await deps.surreal
 93→        .query<[SearchEntityRow[]]>(
 94→          "RETURN fn::entity_search_workspace($query, $limit, $workspace);",
 95→          {
 96→            query,
 97→            limit,
 98→            workspace: workspaceRecord,
 99→          },
100→        )
101→        .collect<[SearchEntityRow[]]>();
102→
103→  const responseRows = rows
104→    .map((row) => ({
105→      id: row.id.id as string,
106→      kind: row.kind,
107→      text: row.text,
108→      confidence: row.confidence,
109→      sourceId: row.sourceMessage.id as string,
110→      sourceKind: "message",
111→    } satisfies SearchEntityResponse))
112→    .slice(0, limit);
113→
114→  logInfo("entity.search.completed", "Entity search completed", {
115→    workspaceId,
116→    projectId,
117→    limit,
118→    resultCount: responseRows.length,
119→    durationMs: elapsedMs(startedAt),
120→  });
121→
122→  return jsonResponse(responseRows, 200);
123→}
