134→function toRecordIdString(record: RecordId<string, string>): string {
135→  return record.id as string;
136→}
137→
138→function toIsoString(value: string | Date): string {
139→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
140→}
141→
142→function normalizeSearchValue(value: string): string {
143→  return value
144→    .trim()
145→    .toLowerCase()
146→    .replace(/[^a-z0-9\s]/g, " ")
147→    .replace(/\s+/g, " ");
148→}
