235→export async function isEntityInWorkspace(
236→  surreal: Surreal,
237→  workspaceRecord: RecordId<"workspace", string>,
238→  entityRecord: GraphEntityRecord,
239→): Promise<boolean> {
240→  const table = entityRecord.table.name;
241→
242→  if (table === "workspace") {
243→    return toRecordIdString(entityRecord) === toRecordIdString(workspaceRecord);
244→  }
245→
246→  if (table === "project") {
247→    const [rows] = await surreal
248→      .query<[Array<{ id: RecordId<"has_project", string> }>]>(
249→        "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
250→        { workspace: workspaceRecord, project: entityRecord },
251→      )
252→      .collect<[Array<{ id: RecordId<"has_project", string> }>]>();
253→
254→    return rows.length > 0;
255→  }
256→
257→  if (table === "person") {
258→    const [rows] = await surreal
259→      .query<[Array<{ id: RecordId<"member_of", string> }>]>(
260→        "SELECT id FROM member_of WHERE `in` = $person AND out = $workspace LIMIT 1;",
261→        { workspace: workspaceRecord, person: entityRecord },
262→      )
263→      .collect<[Array<{ id: RecordId<"member_of", string> }>]>();
264→
265→    return rows.length > 0;
266→  }
267→
268→  if (table === "feature") {
269→    const [rows] = await surreal
270→      .query<[Array<{ id: RecordId<"feature", string> }>]>(
271→        [
272→          "SELECT id",
273→          "FROM feature",
274→          "WHERE id = $feature",
275→          "AND id IN (",
276→          "  SELECT VALUE out",
277→          "  FROM has_feature",
278→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
279→          ");",
280→        ].join(" "),
281→        { workspace: workspaceRecord, feature: entityRecord },
282→      )
283→      .collect<[Array<{ id: RecordId<"feature", string> }>]>();
284→
285→    return rows.length > 0;
286→  }
287→
288→  if (table === "task" || table === "decision" || table === "question") {
289→    const [rows] = await surreal
290→      .query<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>(
291→        `SELECT id FROM ${table} WHERE id = $entity AND workspace = $workspace;`,
292→        { workspace: workspaceRecord, entity: entityRecord },
293→      )
294→      .collect<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>();
295→
296→    return rows.length > 0;
297→  }
298→
299→  return false;
300→}
